#include <bits/stdc++.h>
using namespace std;
int n,ans;
string s[21];
int use[21];
char a;
bool check(string x,string y){
    int lx=x.size(),ly=y.size();
    /*if(lx<=ly){
        int j=0;
        while(x[j]==y[j] && j<lx)
            j++;
        if(j==lx)
            return false;
    }
    if(ly>=ly){
        int j=0;
        while(x[j]==y[j] && j<ly)
            j++;
        if(j==ly)
            return false;
    }*/
    for(int i=0;i<lx;i++){
        int j=0;
        while(x[i+j]==y[j] && j<ly && j+i<lx)
            j++;
        if(j+i==lx)
            return true;
    }
    return false;
}
string merge(string x,string y){
    string tmp=x;
    int lx=x.size(),ly=y.size();
    for(int i=lx-1;i>=0;i--){
        int j=0;
        while(j<ly && j+i<lx && x[i+j]==y[j])
            j++;
        if(j+i==lx){
            while(j<ly){
                tmp+=y[j];
                j++;
            }
            break;
        }
    }
    return tmp;
}
void dfs(int x,string sum){
	//cout<<sum<<endl;
    ans=max(ans,(int)sum.size());
    if(x==1){
        for(int i=1;i<=n;i++)
            if(s[i][0]==a)
                use[i]++,dfs(x+1,s[i]),use[i]--;
    }else{
        for(int i=1;i<=n;i++)
            if(use[i]<2 && check(sum,s[i]))
                use[i]++,dfs(x+1,merge(sum,s[i])),use[i]--;
    }
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        cin>>s[i];
    cin>>a;
    //cout<<merge("abababab","abababab")<<'\n';
    dfs(1,"");
    printf("%d",ans);
    return 0;
}
